            hue: CoreFloat::rem_euclid(finite(hue), 360.0),
            saturation: finite(saturation).clamp(0.0, 1.0),
            lightness: finite(lightness).clamp(0.0, 1.0),
            alpha: finite(alpha).clamp(0.0, 1.0),
