    impl SignatureRasterizer for StubRasterizer {
        fn rasterize(
            &self,
            strokes: &[Vec<RasterPoint>],
            spec: &RasterSpec,
        ) -> Result<RasterImage, RasterError> {
            *self.seen.lock().unwrap() = Some((strokes.to_vec(), spec.clone()));

            Ok(RasterImage {
                format: spec.format,
                bytes: vec![strokes.len() as u8],
            })
        }
    }

