        assert_eq!(AspectRatio::Fixed(100.0).as_ratio(), None);
        assert_eq!(AspectRatio::Fixed(21.0).as_ratio(), None);
        assert_eq!(AspectRatio::Fixed(0.04).as_ratio(), None);
        // The feasible band [MIN, 1/MIN] = [0.05, 20] is accepted at the edges.
